function PomodoroTimer() {
  const WORK = 25 * 60;
  const BREAK = 5 * 60;
  const [seconds, setSeconds] = React.useState(WORK);
  const [isRunning, setIsRunning] = React.useState(false);
  const [mode, setMode] = React.useState('work');
  const [sessions, setSessions] = React.useState(0);

  React.useEffect(() => {
    if (!isRunning) return;
    const id = setInterval(() => {
      setSeconds(s => {
        if (s <= 1) {
          const audio = new Audio('https://actions.google.com/sounds/v1/alarms/beep_short.ogg');
          audio.play().catch(()=>{});
          if (mode === 'work') {
            setSessions(c => c + 1);
            setMode('break');
            return BREAK;
          } else {
            setMode('work');
            return WORK;
          }
        }
        return s - 1;
      });
    }, 1000);
    return () => clearInterval(id);
  }, [isRunning, mode]);

  const fmt = s => `${String(Math.floor(s/60)).padStart(2,'0')}:${String(s%60).padStart(2,'0')}`;
  const pct = mode==='work' ? (WORK-seconds)/WORK : (BREAK-seconds)/BREAK;

  return (
    <div style={{padding:20,fontFamily:'system-ui',textAlign:'center',height:'100%',display:'flex',flexDirection:'column',justifyContent:'center',alignItems:'center'}}>
      <div style={{fontSize:14,textTransform:'uppercase',letterSpacing:2,color:'#888',marginBottom:12}}>
        {mode==='work'?'Focus Time':'Break Time'}
      </div>
      <div style={{fontSize:56,fontWeight:200,fontVariantNumeric:'tabular-nums',marginBottom:16}}>
        {fmt(seconds)}
      </div>
      <div style={{width:200,height:6,background:'#eee',borderRadius:3,marginBottom:20}}>
        <div style={{width:`${pct*100}%`,height:'100%',background:mode==='work'?'#FF9500':'#34C759',borderRadius:3,transition:'width 1s linear'}}/>
      </div>
      <div style={{display:'flex',gap:12}}>
        <button onClick={()=>setIsRunning(!isRunning)}
          style={{padding:'10px 28px',borderRadius:20,border:'none',background:isRunning?'#FF3B30':'#34C759',color:'#fff',fontSize:16,cursor:'pointer',fontWeight:600}}>
          {isRunning?'Pause':'Start'}
        </button>
        <button onClick={()=>{setIsRunning(false);setSeconds(mode==='work'?WORK:BREAK);}}
          style={{padding:'10px 20px',borderRadius:20,border:'1px solid #ccc',background:'#fff',fontSize:16,cursor:'pointer'}}>
          Reset
        </button>
      </div>
      <div style={{marginTop:16,fontSize:13,color:'#888'}}>Sessions completed: {sessions}</div>
    </div>
  );
}
render(<PomodoroTimer/>);
